 1→"use server";
 2→
 3→import { redirect } from "next/navigation";
 4→import { createClient } from "./server";
 5→
 6→export async function signUp(formData: FormData) {
 7→  const supabase = await createClient();
 8→
 9→  const email = formData.get("email") as string;
10→  const password = formData.get("password") as string;
11→  const username = formData.get("username") as string;
12→
13→  const { error } = await supabase.auth.signUp({
14→    email,
15→    password,
16→    options: {
17→      data: { username },
18→    },
19→  });
20→
21→  if (error) {
22→    return { error: error.message };
23→  }
24→
25→  redirect("/");
26→}
27→
28→export async function signIn(formData: FormData) {
29→  const supabase = await createClient();
30→
31→  const email = formData.get("email") as string;
32→  const password = formData.get("password") as string;
33→
34→  const { error } = await supabase.auth.signInWithPassword({
35→    email,
36→    password,
37→  });
38→
39→  if (error) {
40→    return { error: error.message };
41→  }
42→
43→  redirect("/");
44→}
45→
46→export async function signOut() {
47→  const supabase = await createClient();
48→  await supabase.auth.signOut();
49→  redirect("/");
50→}
