  1→import { createClient } from "@/lib/supabase/client";
  2→import type { GuideBuilderState } from "@/hooks/use-guide-builder";
  3→
  4→interface PublishInput {
  5→  state: GuideBuilderState;
  6→  userId: string;
  7→}
  8→
  9→export async function publishGuide({ state, userId }: PublishInput): Promise<string | null> {
 10→  const supabase = createClient();
 11→
 12→  // 1. Insert post
 13→  const { data: post, error: postError } = await supabase
 14→    .from("posts")
 15→    .insert({
 16→      user_id: userId,
 17→      title: state.title.trim(),
 18→      description: state.description.trim(),
 19→      difficulty: state.difficulty,
 20→      time_estimate_minutes: state.timeEstimate,
 21→      is_vibe_coded: state.isVibeCoded,
 22→      guide_type: state.guideType,
 23→      prerequisites: state.prerequisites,
 24→      what_youll_build: state.whatYoullBuild.trim() || null,
 25→      original_json: state.originalJson,
 26→      techs: state.techs,
 27→      category_id: state.categoryId,
 28→    })
 29→    .select("id")
 30→    .single();
 31→
 32→  if (postError || !post) {
 33→    console.error("Failed to create post:", postError?.message);
 34→    return null;
 35→  }
 36→
 37→  const postId = post.id;
 38→
 39→  // 2. Upload media
 40→  if (state.mediaFiles.length > 0) {
 41→    const mediaRows = [];
 42→
 43→    for (let i = 0; i < state.mediaFiles.length; i++) {
 44→      const media = state.mediaFiles[i];
 45→      const ext = media.file.name.split(".").pop();
 46→      const path = `${userId}/${postId}/${i}.${ext}`;
 47→
 48→      const { error: uploadError } = await supabase.storage
 49→        .from("post-media")
 50→        .upload(path, media.file);
 51→
 52→      if (uploadError) {
 53→        console.error("Upload error:", uploadError.message);
 54→        continue;
 55→      }
 56→
 57→      const { data: urlData } = supabase.storage
 58→        .from("post-media")
 59→        .getPublicUrl(path);
 60→
 61→      mediaRows.push({
 62→        post_id: postId,
 63→        url: urlData.publicUrl,
 64→        type: media.type,
 65→        order: i,
 66→      });
 67→    }
 68→
 69→    if (mediaRows.length > 0) {
 70→      await supabase.from("post_media").insert(mediaRows);
 71→    }
 72→  }
 73→
 74→  // 3. Insert guide_blocks (batched)
 75→  const clientIdToRealBlockId = new Map<string, string>();
 76→
 77→  if (state.blocks.length > 0) {
 78→    const blockRows = state.blocks.map((b) => ({
 79→      post_id: postId,
 80→      role: b.role,
 81→      content: b.content,
 82→      tool_action: b.toolAction,
 83→      file_path: b.filePath,
 84→      original_order: b.originalOrder,
 85→      auto_category: b.autoCategory,
 86→      files_touched: b.filesTouched,
 87→    }));
 88→
 89→    for (let i = 0; i < blockRows.length; i += 500) {
 90→      const batch = blockRows.slice(i, i + 500);
 91→      const batchBlocks = state.blocks.slice(i, i + 500);
 92→
 93→      const { data: inserted, error: blockError } = await supabase
 94→        .from("guide_blocks")
 95→        .insert(batch)
 96→        .select("id");
 97→
 98→      if (blockError) {
 99→        console.error("guide_blocks insert error:", blockError.message);
100→        continue;
101→      }
102→
103→      if (inserted) {
104→        for (let j = 0; j < inserted.length; j++) {
105→          clientIdToRealBlockId.set(batchBlocks[j].clientId, inserted[j].id);
106→        }
107→      }
108→    }
109→  }
110→
111→  // 4. Insert guide_steps (batched)
112→  const clientIdToRealStepId = new Map<string, string>();
113→
114→  if (state.steps.length > 0) {
115→    const stepRows = state.steps.map((s) => ({
116→      post_id: postId,
117→      title: s.title.trim() || `Step ${s.order + 1}`,
118→      description: s.description.trim() || null,
119→      author_annotation: s.authorAnnotation.trim() || null,
120→      suggested_prompt: s.suggestedPrompt.trim() || null,
121→      checkpoint_description: s.checkpointDescription.trim() || null,
122→      order: s.order,
123→    }));
124→
125→    const { data: insertedSteps, error: stepError } = await supabase
126→      .from("guide_steps")
127→      .insert(stepRows)
128→      .select("id");
129→
130→    if (stepError) {
131→      console.error("guide_steps insert error:", stepError.message);
132→    } else if (insertedSteps) {
133→      for (let i = 0; i < insertedSteps.length; i++) {
134→        clientIdToRealStepId.set(state.steps[i].clientId, insertedSteps[i].id);
135→      }
136→    }
137→  }
138→
139→  // 5. Insert step_blocks (batched)
140→  const stepBlockRows: {
141→    step_id: string;
142→    block_id: string;
143→    position: number;
144→    display_mode: string;
145→    author_note: string | null;
146→  }[] = [];
147→
148→  for (const step of state.steps) {
149→    const realStepId = clientIdToRealStepId.get(step.clientId);
150→    if (!realStepId) continue;
151→
152→    for (const assignment of step.blockAssignments) {
153→      const realBlockId = clientIdToRealBlockId.get(assignment.blockClientId);
154→      if (!realBlockId) continue;
155→
156→      stepBlockRows.push({
157→        step_id: realStepId,
158→        block_id: realBlockId,
159→        position: assignment.position,
160→        display_mode: assignment.displayMode,
161→        author_note: assignment.authorNote.trim() || null,
162→      });
163→    }
164→  }
165→
166→  if (stepBlockRows.length > 0) {
167→    for (let i = 0; i < stepBlockRows.length; i += 500) {
168→      const batch = stepBlockRows.slice(i, i + 500);
169→      const { error: sbError } = await supabase
170→        .from("step_blocks")
171→        .insert(batch);
172→
173→      if (sbError) {
174→        console.error("step_blocks insert error:", sbError.message);
175→      }
176→    }
177→  }
178→
179→  // 6. Insert chat_messages (backward compat for timeline view)
180→  if (state.blocks.length > 0) {
181→    const chatRows = state.blocks.map((b, i) => ({
182→      post_id: postId,
183→      role: b.role,
184→      content: b.content,
185→      tool_action: b.toolAction,
186→      file_path: b.filePath,
187→      order: i,
188→    }));
189→
190→    for (let i = 0; i < chatRows.length; i += 500) {
191→      const batch = chatRows.slice(i, i + 500);
192→      const { error: chatError } = await supabase
193→        .from("chat_messages")
194→        .insert(batch);
195→
196→      if (chatError) {
197→        console.error("chat_messages insert error:", chatError.message);
198→      }
199→    }
200→  }
201→
202→  return postId;
203→}
