 1→"use client";
 2→
 3→import { useEffect, useState } from "react";
 4→import { createClient } from "@/lib/supabase/client";
 5→import type { User } from "@supabase/supabase-js";
 6→import type { Profile } from "@/types";
 7→
 8→export function useAuth() {
 9→  const [user, setUser] = useState<User | null>(null);
10→  const [profile, setProfile] = useState<Profile | null>(null);
11→  const [loading, setLoading] = useState(true);
12→
13→  useEffect(() => {
14→    let mounted = true;
15→    const supabase = createClient();
16→
17→    async function fetchProfile(userId: string): Promise<Profile | null> {
18→      try {
19→        const { data, error } = await supabase
20→          .from("profiles")
21→          .select("*")
22→          .eq("id", userId)
23→          .single();
24→
25→        if (error) return null;
26→        return data as Profile;
27→      } catch {
28→        return null;
29→      }
30→    }
31→
32→    function handleSession(session: { user: User } | null) {
33→      if (!mounted) return;
34→
35→      const currentUser = session?.user ?? null;
36→      setUser(currentUser);
37→
38→      if (currentUser) {
39→        setLoading(false);
40→        fetchProfile(currentUser.id).then((p) => {
41→          if (mounted) setProfile(p);
42→        });
43→      } else {
44→        setProfile(null);
45→        setLoading(false);
46→      }
47→    }
48→
49→    const { data: { subscription } } = supabase.auth.onAuthStateChange(
50→      (_event, session) => {
51→        handleSession(session);
52→      }
53→    );
54→
55→    return () => {
56→      mounted = false;
57→      subscription.unsubscribe();
58→    };
59→  }, []);
60→
61→  return { user, profile, loading };
62→}
