13→export function BlockSourcePanel() {
14→  const { state, dispatch } = useGuideBuilder();
15→
16→  const handleImport = useCallback(
17→    (messages: ParsedMessage[], rawJson?: string) => {
18→      if (messages.length === 0) {
19→        dispatch({ type: "CLEAR_BLOCKS" });
20→        return;
21→      }
22→
23→      const blocks = messages.map((msg, i) => ({
24→        clientId: clientId(),
25→        role: msg.role,
26→        content: msg.content,
27→        toolAction: msg.toolAction,
28→        filePath: msg.filePath,
29→        originalOrder: i,
30→        autoCategory: categorizeBlock(msg, i, messages.length),
31→        filesTouched: extractFilesTouched(msg),
32→        assignedToStepId: null,
33→      }));
34→
35→      dispatch({
36→        type: "IMPORT_BLOCKS",
37→        payload: {
38→          blocks,
39→          originalJson: rawJson ?? JSON.stringify(messages),
40→        },
41→      });
42→    },
43→    [dispatch]
44→  );
45→
46→  // When blocks are loaded, show the searchable pool
47→  if (state.blocks.length > 0) {
48→    return <BlockPool />;
49→  }
50→
51→  // Otherwise show the chat import
52→  return (
53→    <ChatPickerAdapter onImport={handleImport} />
54→  );
55→}
