57→/**
58→ * Adapter that wraps ChatPicker to intercept the onChange and also pass raw JSON.
59→ */
60→function ChatPickerAdapter({
61→  onImport,
62→}: {
63→  onImport: (messages: ParsedMessage[], rawJson?: string) => void;
64→}) {
65→  const handleChange = useCallback(
66→    (messages: ParsedMessage[]) => {
67→      onImport(messages);
68→    },
69→    [onImport]
70→  );
71→
72→  return <ChatPicker messages={[]} onChange={handleChange} />;
73→}
