 15→
 16→interface ChatPickerProps {
 17→  messages: ParsedMessage[];
 18→  onChange: (messages: ParsedMessage[]) => void;
 19→}
 20→
 21→interface ConversationEntry {
 22→  file: File;
 23→  project: string;
 24→  lastModified: number;
 25→}
 26→
 27→interface ProjectGroup {
 28→  name: string;
 29→  conversations: ConversationEntry[];
 30→}
 31→
 32→const CLAUDE_PATH = "~/.claude/projects/";
 33→
 34→// --- Directory walking helpers ---
 35→
 36→function readEntries(reader: FileSystemDirectoryReader): Promise<FileSystemEntry[]> {
 37→  return new Promise((resolve) => {
 38→    reader.readEntries(
 39→      (entries) => resolve(entries),
 40→      () => resolve([])
 41→    );
 42→  });
 43→}
 44→
 45→function entryToFile(entry: FileSystemFileEntry): Promise<File | null> {
 46→  return new Promise((resolve) => {
 47→    entry.file((f) => resolve(f), () => resolve(null));
 48→  });
 49→}
 50→
 51→async function collectFromProjectDir(
 52→  dirEntry: FileSystemDirectoryEntry
 53→): Promise<File[]> {
 54→  const reader = dirEntry.createReader();
 55→  const files: File[] = [];
 56→
 57→  let batch = await readEntries(reader);
 58→  while (batch.length > 0) {
 59→    for (const child of batch) {
 60→      if (child.isFile && child.name.endsWith(".jsonl")) {
 61→        const f = await entryToFile(child as FileSystemFileEntry);
 62→        if (f) files.push(f);
 63→      }
 64→    }
 65→    batch = await readEntries(reader);
 66→  }
 67→
 68→  return files;
 69→}
 70→
 71→async function discoverConversations(
 72→  items: DataTransferItemList
 73→): Promise<ConversationEntry[]> {
 74→  const fsEntries: FileSystemEntry[] = [];
 75→  for (let i = 0; i < items.length; i++) {
 76→    const entry = items[i].webkitGetAsEntry?.();
 77→    if (entry) fsEntries.push(entry);
 78→  }
 79→
 80→  const entries: ConversationEntry[] = [];
 81→
 82→  for (const entry of fsEntries) {
 83→    if (entry.isFile && entry.name.endsWith(".jsonl")) {
 84→      const f = await entryToFile(entry as FileSystemFileEntry);
 85→      if (f) {
 86→        entries.push({ file: f, project: "Dropped file", lastModified: f.lastModified });
 87→      }
 88→      continue;
 89→    }
 90→
 91→    if (!entry.isDirectory) continue;
 92→
 93→    const dirEntry = entry as FileSystemDirectoryEntry;
 94→    const reader = dirEntry.createReader();
 95→    const allChildren: FileSystemEntry[] = [];
 96→    let batch = await readEntries(reader);
 97→    while (batch.length > 0) {
 98→      allChildren.push(...batch);
 99→      batch = await readEntries(reader);
100→    }
101→
102→    const jsonlChildren = allChildren.filter(
103→      (c) => c.isFile && c.name.endsWith(".jsonl")
104→    );
105→
106→    if (jsonlChildren.length > 0) {
107→      for (const child of jsonlChildren) {
108→        const f = await entryToFile(child as FileSystemFileEntry);
109→        if (f) {
110→          entries.push({ file: f, project: dirEntry.name, lastModified: f.lastModified });
111→        }
112→      }
113→    } else {
114→      for (const child of allChildren) {
115→        if (child.isDirectory) {
116→          const projectFiles = await collectFromProjectDir(
117→            child as FileSystemDirectoryEntry
118→          );
119→          for (const f of projectFiles) {
120→            entries.push({ file: f, project: child.name, lastModified: f.lastModified });
121→          }
122→        }
123→      }
124→    }
125→  }
126→
127→  return entries;
128→}
129→
130→function formatProjectName(encoded: string): string {
131→  const parts = encoded.replace(/^-/, "").split("-");
132→  const stopWords = new Set(["users", "home", "documents", "proyectos", "projects", "desktop", "repos", "code", "dev", "src"]);
133→  let startIdx = 0;
134→  for (let i = 0; i < parts.length; i++) {
135→    if (stopWords.has(parts[i].toLowerCase())) {
136→      startIdx = i + 1;
137→    }
138→  }
139→  const meaningful = parts.slice(startIdx);
140→  return meaningful.length > 0 ? meaningful.join("-") : encoded;
141→}
142→
143→function groupByProject(entries: ConversationEntry[]): ProjectGroup[] {
144→  const map = new Map<string, ConversationEntry[]>();
145→  for (const entry of entries) {
146→    const existing = map.get(entry.project) ?? [];
147→    existing.push(entry);
148→    map.set(entry.project, existing);
149→  }
150→  return Array.from(map.entries())
151→    .map(([name, conversations]) => ({
152→      name,
153→      conversations: conversations.sort((a, b) => b.lastModified - a.lastModified),
154→    }))
155→    .sort((a, b) => b.conversations[0].lastModified - a.conversations[0].lastModified);
156→}
