278→export function ChatPicker({ messages, onChange }: ChatPickerProps) {
279→  const inputRef = useRef<HTMLInputElement>(null);
280→  const [loading, setLoading] = useState(false);
281→  const [error, setError] = useState("");
282→  const [dragging, setDragging] = useState(false);
283→  const [copied, setCopied] = useState(false);
284→
285→  const [projects, setProjects] = useState<ProjectGroup[]>([]);
286→  const [expandedProject, setExpandedProject] = useState<string | null>(null);
287→
288→  async function processFile(file: File) {
289→    try {
290→      const text = await file.text();
291→      const parsed = parseClaudeCodeJsonl(text);
292→      if (parsed.length === 0) {
293→        setError("This file is empty or couldn't be parsed.");
294→        setLoading(false);
295→        return;
296→      }
297→      // Keep projects so user can go back
298→      onChange(parsed);
299→    } catch {
300→      setError("Failed to read the conversation file.");
301→    }
302→    setLoading(false);
303→  }
304→
305→  async function handleFileSelect(e: React.ChangeEvent<HTMLInputElement>) {
306→    const file = e.target.files?.[0];
307→    if (!file) return;
308→    setLoading(true);
309→    setError("");
310→    await processFile(file);
311→  }
312→
313→  const handleDragOver = useCallback((e: React.DragEvent) => {
314→    e.preventDefault();
315→    e.stopPropagation();
316→    setDragging(true);
317→  }, []);
318→
319→  const handleDragLeave = useCallback((e: React.DragEvent) => {
320→    e.preventDefault();
321→    e.stopPropagation();
322→    setDragging(false);
323→  }, []);
324→
325→  const handleDrop = useCallback(async (e: React.DragEvent) => {
326→    e.preventDefault();
327→    e.stopPropagation();
328→    setDragging(false);
329→    setLoading(true);
330→    setError("");
331→    setProjects([]);
332→
333→    const droppedFiles = Array.from(e.dataTransfer.files);
334→    const directJsonl = droppedFiles.find((f) => f.name.endsWith(".jsonl"));
335→    if (directJsonl) {
336→      await processFile(directJsonl);
337→      return;
338→    }
339→
340→    if (e.dataTransfer.items.length > 0) {
341→      const entries = await discoverConversations(e.dataTransfer.items);
342→      if (entries.length > 0) {
343→        if (entries.length === 1) {
344→          await processFile(entries[0].file);
345→          return;
346→        }
347→        const grouped = groupByProject(entries);
348→        setProjects(grouped);
349→        setExpandedProject(grouped[0].name);
350→        setLoading(false);
351→        return;
352→      }
353→    }
354→
355→    setError("No conversations found. Drop the ~/.claude/projects/ folder or a .jsonl file.");
356→    setLoading(false);
357→  }, []);
358→
359→  async function selectConversation(entry: ConversationEntry) {
360→    setLoading(true);
361→    setError("");
362→    await processFile(entry.file);
363→  }
364→
365→  async function copyPath() {
366→    await navigator.clipboard.writeText(CLAUDE_PATH);
367→    setCopied(true);
368→    setTimeout(() => setCopied(false), 2000);
369→  }
370→
371→  function goBackToPicker() {
372→    onChange([]);
373→    setError("");
374→  }
375→
376→  function clear() {
377→    onChange([]);
378→    setProjects([]);
379→    setExpandedProject(null);
380→    setError("");
381→    if (inputRef.current) inputRef.current.value = "";
382→  }
383→
384→  function removeProject(name: string) {
385→    const updated = projects.filter((p) => p.name !== name);
386→    if (updated.length === 0) {
387→      clear();
388→    } else {
389→      setProjects(updated);
390→      if (expandedProject === name) {
