410→
411→  const humanCount = messages.filter((m) => m.role === "human").length;
412→  const assistantCount = messages.filter((m) => m.role === "assistant").length;
413→
414→  // --- Picker view ---
415→  if (projects.length > 0 && messages.length === 0) {
