  1→"use client";
  2→
  3→import { useRef } from "react";
  4→import { ImagePlus, X, Film } from "lucide-react";
  5→import { cn } from "@/lib/utils";
  6→
  7→export interface MediaFile {
  8→  file: File;
  9→  preview: string;
 10→  type: "image" | "video";
 11→}
 12→
 13→interface MediaUploadProps {
 14→  files: MediaFile[];
 15→  onChange: (files: MediaFile[]) => void;
 16→  max?: number;
 17→}
 18→
 19→export function MediaUpload({ files, onChange, max = 6 }: MediaUploadProps) {
 20→  const inputRef = useRef<HTMLInputElement>(null);
 21→
 22→  function handleFiles(fileList: FileList | null) {
 23→    if (!fileList) return;
 24→
 25→    const newFiles: MediaFile[] = [];
 26→    for (let i = 0; i < fileList.length && files.length + newFiles.length < max; i++) {
 27→      const file = fileList[i];
 28→      const isVideo = file.type.startsWith("video/");
 29→      const isImage = file.type.startsWith("image/");
 30→      if (!isVideo && !isImage) continue;
 31→
 32→      newFiles.push({
 33→        file,
 34→        preview: URL.createObjectURL(file),
 35→        type: isVideo ? "video" : "image",
 36→      });
 37→    }
 38→
 39→    onChange([...files, ...newFiles]);
 40→  }
 41→
 42→  function removeFile(index: number) {
 43→    URL.revokeObjectURL(files[index].preview);
 44→    onChange(files.filter((_, i) => i !== index));
 45→  }
 46→
 47→  return (
 48→    <div className="space-y-3">
 49→      <div className="grid grid-cols-3 gap-3">
 50→        {files.map((media, i) => (
 51→          <div key={media.preview} className="group relative aspect-video overflow-hidden rounded-lg bg-muted">
 52→            {media.type === "video" ? (
 53→              <video
 54→                src={media.preview}
 55→                className="h-full w-full object-cover"
 56→              />
 57→            ) : (
 58→              <img
 59→                src={media.preview}
 60→                alt=""
 61→                className="h-full w-full object-cover"
 62→              />
 63→            )}
 64→            {media.type === "video" && (
 65→              <div className="absolute bottom-1 left-1">
 66→                <Film size={14} className="text-white drop-shadow" />
 67→              </div>
 68→            )}
 69→            <button
 70→              type="button"
 71→              onClick={() => removeFile(i)}
 72→              className="absolute top-1 right-1 flex h-6 w-6 items-center justify-center rounded-full bg-black/60 text-white opacity-0 group-hover:opacity-100 transition-opacity"
 73→            >
 74→              <X size={12} />
 75→            </button>
 76→          </div>
 77→        ))}
 78→
 79→        {files.length < max && (
 80→          <button
 81→            type="button"
 82→            onClick={() => inputRef.current?.click()}
 83→            className={cn(
 84→              "flex aspect-video flex-col items-center justify-center gap-1 rounded-lg",
 85→              "bg-muted text-muted-foreground",
 86→              "hover:text-foreground transition-colors",
 87→              "cursor-pointer"
 88→            )}
 89→          >
 90→            <ImagePlus size={20} />
 91→            <span className="text-xs">Add media</span>
 92→          </button>
 93→        )}
 94→      </div>
 95→
 96→      <input
 97→        ref={inputRef}
 98→        type="file"
 99→        accept="image/*,video/*"
100→        multiple
101→        className="hidden"
102→        onChange={(e) => handleFiles(e.target.files)}
103→      />
104→    </div>
105→  );
106→}
