51→export function formatJoinDate(dateString: string): string {
52→  const date = new Date(dateString);
53→  const month = date.toLocaleString("en-US", { month: "short" });
54→  const year = date.getFullYear();
55→  return `Joined ${month} ${year}`;
56→}
